/**
 * Output: 1 row per trigger "schedulabile"
 * - include: scheduleTrigger, cron
 * - exclude: webhook, errorTrigger, manualTrigger (configurabile)
 */

const INCLUDE_MANUAL = false; // metti true se vuoi includere manualTrigger come "Evento (manual)"

const pad2 = (n) => String(n ?? 0).padStart(2, '0');
const DAY_NUM_TO_ICAL = { 1: 'MO', 2: 'TU', 3: 'WE', 4: 'TH', 5: 'FR', 6: 'SA', 7: 'SU' };
const DAY_STR_TO_ICAL = {
  mon: 'MO', monday: 'MO', mo: 'MO',
  tue: 'TU', tuesday: 'TU', tu: 'TU',
  wed: 'WE', wednesday: 'WE', we: 'WE',
  thu: 'TH', thursday: 'TH', th: 'TH',
  fri: 'FR', friday: 'FR', fr: 'FR',
  sat: 'SA', saturday: 'SA', sa: 'SA',
  sun: 'SU', sunday: 'SU', su: 'SU',
};
const icalToIt = { MO: 'lun', TU: 'mar', WE: 'mer', TH: 'gio', FR: 'ven', SA: 'sab', SU: 'dom' };

function normalizeByDay(value) {
  if (value == null) return null;
  if (Array.isArray(value)) {
    const mapped = value
      .map(v => normalizeByDay(v))
      .flatMap(v => (v ? v.split(',') : []));
    const uniq = [...new Set(mapped)].filter(Boolean);
    return uniq.length ? uniq.join(',') : null;
  }
  if (typeof value === 'number') return DAY_NUM_TO_ICAL[value] ?? null;
  if (typeof value === 'string') {
    const s = value.trim();
    if (!s) return null;
    if (/^(MO|TU|WE|TH|FR|SA|SU)(,(MO|TU|WE|TH|FR|SA|SU))*$/i.test(s)) return s.toUpperCase();
    const lower = s.toLowerCase();
    if (DAY_STR_TO_ICAL[lower]) return DAY_STR_TO_ICAL[lower];
    const asNum = Number(lower);
    if (!Number.isNaN(asNum)) return DAY_NUM_TO_ICAL[asNum] ?? null;
  }
  return null;
}

function humanSchedule(s) {
  if (!s || !s.freq) return '';

  const it = s.interval ?? 1;

  if (s.freq === 'minutely') return it === 1 ? 'Ogni minuto' : `Ogni ${it} minuti`;
  if (s.freq === 'hourly')   return `Ogni ora :${pad2(s.atMinute ?? 0)}`;
  if (s.freq === 'daily')    return `Ogni giorno ${pad2(s.atHour)}:${pad2(s.atMinute)}`;

  if (s.freq === 'weekly') {
    const days = (s.byDay ?? '')
      .split(',')
      .filter(Boolean)
      .map(d => icalToIt[d] ?? d)
      .join(', ');
    const dayTxt = days ? `Ogni ${days}` : 'Ogni settimana';
    return `${dayTxt} ${pad2(s.atHour)}:${pad2(s.atMinute)}`;
  }

  if (s.freq === 'monthly') {
    const dom = s.byMonthDay ?? '?';
    return `Ogni mese (giorno ${dom}) ${pad2(s.atHour)}:${pad2(s.atMinute)}`;
  }

  if (s.freq === 'cron') {
    return s.cronExpression ? `Cron: ${s.cronExpression}` : 'Cron';
  }

  if (s.freq === 'event') {
    return s.eventType ? `Evento (${s.eventType})` : 'Evento';
  }

  return '';
}

/**
 * Robust scheduleTrigger parser:
 * handles:
 *  - rule.interval[0].field present (minutes/hours/days/weeks/months)
 *  - field missing but triggerAtHour/triggerAtMinute present (infer daily)
 *  - weekly/monthly signals via triggerAtDay / dayOfMonth / weekday / days
 */
function parseScheduleTrigger(node) {
  const rule = node?.parameters?.rule ?? null;
  const tz = node?.parameters?.timezone || null;

  const intervals = rule?.interval;
  const i = Array.isArray(intervals) && intervals.length ? intervals[0] : (rule ?? {});

  const out = {
    triggerType: 'scheduleTrigger',
    freq: null,
    interval: 1,
    atHour: null,
    atMinute: null,
    byDay: null,
    byMonthDay: null,
    timezone: tz,
    scheduleRaw: { rule },
    cronExpression: null,
  };

  // If cronExpression exists here
  if (rule?.cronExpression) {
    out.freq = 'cron';
    out.cronExpression = rule.cronExpression;
    out.scheduleHuman = humanSchedule(out);
    return out;
  }

  const field = i.field;

  // Helper reads (some versions use different keys)
  const atHour = i.triggerAtHour ?? i.atHour ?? null;
  const atMinute = i.triggerAtMinute ?? i.atMinute ?? null;
  const trigDay = i.triggerAtDay ?? i.weekday ?? i.dayOfWeek ?? i.days ?? null;
  const monthDay = i.dayOfMonth ?? i.monthDay ?? null;

  // If field is present, use it
  if (field === 'minutes') {
    out.freq = 'minutely';
    out.interval = i.minutesInterval ?? i.interval ?? 1;

  } else if (field === 'hours') {
    out.freq = 'hourly';
    out.interval = i.hoursInterval ?? i.interval ?? 1;
    out.atMinute = atMinute ?? 0;

  } else if (field === 'days') {
    out.freq = 'daily';
    out.interval = i.daysInterval ?? i.interval ?? 1;
    out.atHour = atHour ?? 0;
    out.atMinute = atMinute ?? 0;

  } else if (field === 'weeks') {
    out.freq = 'weekly';
    out.interval = i.weeksInterval ?? i.interval ?? 1;
    out.atHour = atHour ?? 0;
    out.atMinute = atMinute ?? 0;
    out.byDay = normalizeByDay(trigDay);

  } else if (field === 'months') {
    out.freq = 'monthly';
    out.interval = i.monthsInterval ?? i.interval ?? 1;
    out.atHour = atHour ?? 0;
    out.atMinute = atMinute ?? 0;
    const dom = i.triggerAtDay ?? monthDay;
    const domNum = typeof dom === 'number' ? dom : Number(dom);
    out.byMonthDay = Number.isNaN(domNum) ? null : domNum;

  } else {
    // field missing -> infer
    const hasHour = atHour !== null;
    const hasMinute = atMinute !== null;

    const byDay = normalizeByDay(trigDay);
    const dom = i.triggerAtDay ?? monthDay;

    if (byDay) {
      // weekly-ish
      out.freq = 'weekly';
      out.atHour = atHour ?? 0;
      out.atMinute = atMinute ?? 0;
      out.byDay = byDay;
    } else if (dom != null) {
      // monthly-ish
      out.freq = 'monthly';
      out.atHour = atHour ?? 0;
      out.atMinute = atMinute ?? 0;
      const domNum = typeof dom === 'number' ? dom : Number(dom);
      out.byMonthDay = Number.isNaN(domNum) ? null : domNum;
    } else if (hasHour || hasMinute) {
      // assume daily at HH:MM
      out.freq = 'daily';
      out.atHour = atHour ?? 0;
      out.atMinute = atMinute ?? 0;
    } else if (rule?.interval?.[0]?.field === undefined && Array.isArray(rule?.interval) && rule.interval.length) {
      // still unknown shape; keep as unknown for debugging
      out.freq = 'unknown';
    } else {
      out.freq = 'unknown';
    }
  }

  out.scheduleHuman = humanSchedule(out);
  return out;
}

function parseCronNode(node) {
  const p = node?.parameters ?? {};
  const cron =
    p.cronExpression ||
    p.expression ||
    p.cron ||
    p.rules?.[0]?.cronExpression ||
    null;

  return {
    triggerType: 'cron',
    freq: 'cron',
    interval: 1,
    atHour: null,
    atMinute: null,
    byDay: null,
    byMonthDay: null,
    timezone: p.timezone || null,
    cronExpression: cron,
    scheduleRaw: { parameters: p },
    scheduleHuman: humanSchedule({ freq: 'cron', cronExpression: cron }),
  };
}

function getTags(wf) {
  const tags = wf.tags ?? [];
  return tags.map(t => (typeof t === 'string' ? t : t.name)).filter(Boolean);
}

function getNodes(wf) {
  return wf.activeVersion?.nodes || wf.nodes || [];
}

const output = [];

for (const item of $input.all()) {
  const wf = item.json;
  const nodes = getNodes(wf);

  // pick triggers
  const triggers = nodes.filter(n => {
    if (n.type === 'n8n-nodes-base.webhook') return false;          // EXCLUDE
    if (n.type === 'n8n-nodes-base.errorTrigger') return false;     // EXCLUDE
    if (n.type === 'n8n-nodes-base.manualTrigger') return INCLUDE_MANUAL; // optional
    return (
      n.type === 'n8n-nodes-base.scheduleTrigger' ||
      n.type === 'n8n-nodes-base.cron'
    );
  });

  // If no schedulable triggers: do nothing (keeps sheet clean)
  if (triggers.length === 0) continue;

  for (const t of triggers) {
    const sched =
      t.type === 'n8n-nodes-base.scheduleTrigger' ? parseScheduleTrigger(t)
      : t.type === 'n8n-nodes-base.cron' ? parseCronNode(t)
      : { triggerType: 'event', freq: 'event', scheduleHuman: 'Evento', scheduleRaw: { parameters: t.parameters ?? {} } };

    output.push({
      json: {
        WorkflowID: wf.id,
        Workflow: wf.name,
        Tags: JSON.stringify(getTags(wf)),
        Active: !!wf.active,

        triggerType: sched.triggerType,
        freq: sched.freq ?? '',
        interval: sched.interval ?? '',
        atHour: sched.atHour ?? '',
        atMinute: sched.atMinute ?? '',
        byDay: sched.byDay ?? '',
        byMonthDay: sched.byMonthDay ?? '',
        timezone: sched.timezone ?? (wf.settings?.timezone || ''),

        schedule: sched.scheduleHuman ?? '',
        "Schedule-RAW": JSON.stringify(sched.scheduleRaw ?? {}),
      }
    });
  }
}

return output;

/**
 * Google Calendar payload builder.
 *
 * Schedules supportati:
 * - DAILY  "Ogni giorno HH:MM"              → 1 evento Daily
 * - WEEKLY "Ogni settimana HH:MM"           → 1 evento Weekly
 * - WEEKLY "Ogni lun HH:MM" / "Ogni lun, mer HH:MM" → 1 evento Weekly
 * - MONTHLY "Ogni mese (giorno N) HH:MM"   → 1 evento Monthly
 * - HOURLY "Ogni ora :MM"                   → 1 evento Daily (FIX: era 24, ora 1)
 * - MINUTELY / CRON                         → SKIP
 *
 * FIX: Hourly ora produce 1 solo evento (era 24 → rate limit).
 * FIX: Aggiunto supporto weekly con giorni e monthly.
 */

const DEFAULT_TIMEZONE  = 'Europe/Rome';
const EVENT_DURATION_MIN = 5;

const SKIP_WORKFLOW_NAME_CONTAINS = ['Workflow Scheduling Extraction'];
const SKIP_SCHEDULE_REGEXES = [
  /ogni\s+minuto/i,
  /ogni\s+\d+\s+minut/i,
];

const FREQ = {
  DAILY:   'Daily',
  WEEKLY:  'Weekly',
  MONTHLY: 'Monthly',
};

const pad2 = (n) => String(n ?? 0).padStart(2, '0');

function localDateTimeString(d) {
  return `${d.getFullYear()}-${pad2(d.getMonth()+1)}-${pad2(d.getDate())}T${pad2(d.getHours())}:${pad2(d.getMinutes())}:${pad2(d.getSeconds())}`;
}

function startEndForToday(atHour, atMinute) {
  const now = new Date();
  const s = new Date(now.getFullYear(), now.getMonth(), now.getDate(), atHour ?? 0, atMinute ?? 0, 0);
  const e = new Date(s);
  e.setMinutes(e.getMinutes() + EVENT_DURATION_MIN);
  return { start: localDateTimeString(s), end: localDateTimeString(e) };
}

function shouldSkip(r) {
  const wfName = String(r.Workflow || r.workflow || r.name || '');
  if (SKIP_WORKFLOW_NAME_CONTAINS.some(x => wfName.includes(x))) return true;
  const sched = String(r.schedule || '');
  if (SKIP_SCHEDULE_REGEXES.some(rx => rx.test(sched))) return true;
  return false;
}

/**
 * Parses humanSchedule string → schedule type object.
 * Returns null if schedule type is unsupported/should be skipped.
 */
function parseSchedule(scheduleHuman) {
  if (!scheduleHuman) return null;
  const txt = String(scheduleHuman).trim().toLowerCase();

  // "Ogni giorno 09:30"
  const mDaily = txt.match(/ogni\s+giorno\s+(\d{1,2})\s*[:.]\s*(\d{1,2})/);
  if (mDaily) {
    const h = Number(mDaily[1]), m = Number(mDaily[2]);
    if (h >= 0 && h <= 23 && m >= 0 && m <= 59) return { type: 'daily', atHour: h, atMinute: m };
  }

  // "Ogni settimana 07:00" (nessun giorno specifico)
  const mWeekly = txt.match(/ogni\s+settimana\s+(\d{1,2})\s*[:.]\s*(\d{1,2})/);
  if (mWeekly) {
    const h = Number(mWeekly[1]), m = Number(mWeekly[2]);
    if (h >= 0 && h <= 23 && m >= 0 && m <= 59) return { type: 'weekly', atHour: h, atMinute: m };
  }

  // "Ogni lun 07:00" / "Ogni lun, mer 07:00" (FIX: weekly con giorni specifici)
  const mWeeklyDay = txt.match(/^ogni\s+(?:lun|mar|mer|gio|ven|sab|dom)[\w,\s]*\s+(\d{1,2})[:.]\s*(\d{1,2})/);
  if (mWeeklyDay) {
    const h = Number(mWeeklyDay[1]), m = Number(mWeeklyDay[2]);
    if (h >= 0 && h <= 23 && m >= 0 && m <= 59) return { type: 'weekly', atHour: h, atMinute: m };
  }

  // "Ogni mese (giorno N) HH:MM" (FIX: aggiunto monthly)
  const mMonthly = txt.match(/ogni\s+mese.*\s+(\d{1,2}):(\d{2})\s*$/);
  if (mMonthly) {
    const h = Number(mMonthly[1]), m = Number(mMonthly[2]);
    if (h >= 0 && h <= 23 && m >= 0 && m <= 59) return { type: 'monthly', atHour: h, atMinute: m };
  }

  // "Ogni ora :45" o "Ogni ora .00" (FIX: ora produce 1 evento invece di 24)
  const mHourly = txt.match(/ogni\s+ora\s*[.:]\s*(\d{1,2})/);
  if (mHourly) {
    const m = Number(mHourly[1]);
    if (m >= 0 && m <= 59) return { type: 'hourly', minute: m };
  }

  return null;  // cron, unknown, minutely → skip
}

function buildCommon(r) {
  const wfName = r.Workflow || r.workflow || r.name || 'workflow';
  const description =
`WorkflowID: ${r.WorkflowID || r.workflowId || r.id || ''}
Tags: ${r.Tags || r.tags || ''}
TriggerType: ${r.triggerType || ''}
Schedule: ${r.schedule || ''}`;
  return { summaryBase: `n8n | ${wfName}`, description };
}

const out = [];

for (const item of $input.all()) {
  const r = item.json;
  if (shouldSkip(r)) continue;

  const parsed = parseSchedule(r.schedule);
  if (!parsed) {
    console.log(`SKIP (schedule non supportato): ${r.WorkflowID} | ${r.schedule}`);
    continue;
  }

  const timezone = r.timezone || DEFAULT_TIMEZONE;
  const { summaryBase, description } = buildCommon(r);

  if (parsed.type === 'daily') {
    const { start, end } = startEndForToday(parsed.atHour, parsed.atMinute);
    out.push({ json: { ...r, calendarPayload: { summary: summaryBase, description, start, end, timezone, repeatFrequency: FREQ.DAILY, repeatUntil: null } } });
  }

  if (parsed.type === 'weekly') {
    const { start, end } = startEndForToday(parsed.atHour, parsed.atMinute);
    out.push({ json: { ...r, calendarPayload: { summary: summaryBase, description, start, end, timezone, repeatFrequency: FREQ.WEEKLY, repeatUntil: null } } });
  }

  if (parsed.type === 'monthly') {
    const { start, end } = startEndForToday(parsed.atHour, parsed.atMinute);
    out.push({ json: { ...r, calendarPayload: { summary: summaryBase, description, start, end, timezone, repeatFrequency: FREQ.MONTHLY, repeatUntil: null } } });
  }

  if (parsed.type === 'hourly') {
    // FIX: 1 evento Daily invece di 24 (riduceva a ~100 API calls → rate limit)
    // L'evento è collocato a 00:MM e si ripete ogni giorno, con label "ogni ora :MM"
    const { start, end } = startEndForToday(0, parsed.minute);
    out.push({
      json: {
        ...r,
        calendarPayload: {
          summary: `${summaryBase} (ogni ora :${pad2(parsed.minute)})`,
          description,
          start,
          end,
          timezone,
          repeatFrequency: FREQ.DAILY,
          repeatUntil: null,
        }
      }
    });
  }
}

return out;

/**
 * Detect Changes - confronta 'schedule' (stringa human) tra stato corrente e Sheets.
 *
 * Logica:
 *   - On Calendar vuoto O schedule salvato vuoto → CREATE
 *   - schedule corrente ≠ schedule salvato → UPDATE
 *   - schedule è cron/minutely E già su Calendar → SKIP (evita loop 410 su delete)
 *   - altrimenti → SKIP
 */

// Schedule types che RRULE non può gestire — non creare nuovi eventi per questi
const UNSUPPORTED_REGEXES = [
  /ogni\s+minuto/i,
  /ogni\s+\d+\s+minut/i,
  /^cron:/i,
];

function isUnsupported(schedule) {
  return !schedule || UNSUPPORTED_REGEXES.some(rx => rx.test(String(schedule).trim()));
}

return items.map(item => {
  const data = item.json;

  const currentSchedule = String(data.current_schedule ?? '');
  const savedSchedule   = String(data.schedule ?? '');
  const onCalendar      = data['On Calendar'] || '';
  const workflowId      = data.WorkflowID || data.current_WorkflowID || '';

  console.log(`=== ${workflowId} | current="${currentSchedule}" | saved="${savedSchedule}" | onCal="${onCalendar}"`);

  if (!workflowId) {
    return { json: { ...data, action: 'skip', scheduleChanged: false, changedFields: '' } };
  }

  let action = 'skip';
  let scheduleChanged = false;

  const savedIsEmpty  = !savedSchedule;
  const isNewWorkflow = !onCalendar || savedIsEmpty;

  if (isNewWorkflow) {
    // Nuovo workflow: crea solo se lo schedule è supportato da RRULE
    if (isUnsupported(currentSchedule)) {
      action = 'skip';
      console.log('→ skip (nuovo ma schedule non supportato da RRULE)');
    } else {
      action = 'create';
      console.log('→ create (nuovo)');
    }

  } else if (onCalendar === 'YES') {

    if (currentSchedule !== savedSchedule) {
      // Schedule cambiato
      if (isUnsupported(currentSchedule)) {
        // Nuovo schedule non supportabile → skip, lascia evento vecchio su Calendar
        // (l'evento sarà stale ma non causa loop 410)
        action = 'skip';
        console.log('→ skip (schedule cambiato in tipo non supportato - lascia evento esistente)');
      } else {
        action = 'update';
        scheduleChanged = true;
        console.log(`→ update (schedule cambiato: "${currentSchedule}" vs "${savedSchedule}")`);
      }
    } else {
      action = 'skip';
      console.log('→ skip (invariato)');
    }

  } else {
    // On Calendar = 'NO'
    if (isUnsupported(currentSchedule)) {
      action = 'skip';
      console.log('→ skip (On Calendar=NO, schedule non supportato)');
    } else {
      action = 'create';
      console.log('→ create (On Calendar=NO)');
    }
  }

  return {
    json: {
      ...data,
      action,
      scheduleChanged,
      changedFields: scheduleChanged ? 'schedule' : '',
      _debug: { workflowId, currentSchedule, savedSchedule, onCalendar, isNewWorkflow }
    }
  };
});

// FIX: usa ?? '' (non || '') per non perdere valori numerici come atHour=0 o atMinute=0
return items.map(item => {
  return {
    json: {
      ...item.json,
      current_schedule:    item.json.schedule    ?? '',
      current_freq:        item.json.freq        ?? '',
      current_atHour:      String(item.json.atHour   != null ? item.json.atHour   : ''),
      current_atMinute:    String(item.json.atMinute != null ? item.json.atMinute : ''),
      current_byDay:       item.json.byDay       ?? '',
      current_byMonthDay:  String(item.json.byMonthDay != null ? item.json.byMonthDay : ''),
      current_interval:    String(item.json.interval  != null ? item.json.interval  : ''),
      current_WorkflowID:  item.json.WorkflowID  ?? ''
    }
  };
});

/**
 * Match manuale: combina i dati correnti con quelli salvati dal foglio.
 * FIX: Calendar_EventID ora propagato correttamente (serve per cancellare eventi vecchi).
 */

const currentWorkflows = $('Code: save current values').all();
const sheetRows = items;

console.log(`Current workflows: ${currentWorkflows.length}`);
console.log(`Sheet rows: ${sheetRows.length}`);

const savedMap = {};
for (const row of sheetRows) {
  const wfId = row.json.WorkflowID;
  if (wfId) savedMap[wfId] = row.json;
}

console.log(`Found ${Object.keys(savedMap).length} unique workflows in sheet`);

const output = currentWorkflows.map(current => {
  const wfId = current.json.WorkflowID;
  const saved = savedMap[wfId] || {};
  const hasSavedData = Object.keys(saved).length > 0;

  return {
    json: {
      ...current.json,

      // Dati salvati su Sheets (usa null-coalesce per non perdere valori numerici tipo 0)
      schedule:         saved.schedule          || '',
      freq:             saved.freq              || '',
      atHour:           saved.atHour   != null  ? saved.atHour   : '',
      atMinute:         saved.atMinute != null  ? saved.atMinute : '',
      byDay:            saved.byDay             || '',
      byMonthDay:       saved.byMonthDay != null ? saved.byMonthDay : '',
      interval:         saved.interval != null  ? saved.interval : '',
      'On Calendar':    saved['On Calendar']    || '',
      // ✅ FIX CRITICO: Calendar_EventID era mancante → UPDATE non cancellava mai i vecchi eventi
      'Calendar_EventID': saved['Calendar_EventID'] || '',

      _matchDebug: {
        workflowId:       wfId,
        foundInSheet:     hasSavedData,
        totalInSheet:     Object.keys(savedMap).length,
        savedSchedule:    saved.schedule           || 'EMPTY',
        currentSchedule:  current.json.current_schedule || 'EMPTY',
        calendarEventID:  saved['Calendar_EventID'] || 'EMPTY',
      }
    }
  };
});

console.log(`Returning ${output.length} merged items`);
return output;

/**
 * Post-create: aggrega gli event ID di Google Calendar per workflowId.
 *
 * Input: N items da 'Create an event' (risposta GCal - uno per evento creato)
 * Cross-ref: $('Code: RRULE').all() per recuperare i dati workflow originali
 * Output: 1 item per workflowId -> Sheets:OnCalendar=YES
 */

const allRruleItems = $('Code: RRULE').all();
const byWorkflow = {};

for (let i = 0; i < items.length; i++) {
  const created = items[i].json;
  const rruleItem = allRruleItems[i];
  if (!rruleItem) continue;

  const d = rruleItem.json;
  const wfId = d.WorkflowID || d.current_WorkflowID || '';
  if (!wfId) continue;

  if (!byWorkflow[wfId]) {
    byWorkflow[wfId] = { data: d, eventIds: [] };
  }
  const eventId = created.id || '';
  if (eventId) byWorkflow[wfId].eventIds.push(eventId);
}

return Object.entries(byWorkflow).map(([wfId, { data: d, eventIds }]) => ({
  json: {
    WorkflowID: wfId,
    Workflow: d.Workflow || '',
    Tags: d.Tags || '',
    triggerType: d.triggerType || '',
    schedule: d.current_schedule || d.schedule || '',
    freq: d.current_freq || d.freq || '',
    atHour: String(d.current_atHour ?? d.atHour ?? ''),
    atMinute: String(d.current_atMinute ?? d.atMinute ?? ''),
    byDay: String(d.current_byDay ?? d.byDay ?? ''),
    byMonthDay: String(d.current_byMonthDay ?? d.byMonthDay ?? ''),
    interval: String(d.current_interval ?? d.interval ?? ''),
    'On Calendar': 'YES',
    Calendar_EventID: eventIds.join(' '),
    calendarLastSync: new Date().toISOString().split('T')[0]
  }
}));

/**
 * Split eventIds: estrae un item per Calendar_EventID da eliminare.
 *
 * Input: items da Switch[update] (hanno Calendar_EventID spazio-separato)
 * Output: 1 item per eventId { calendarEventIdToDelete: 'gCal_event_id' }
 *
 * Se Calendar_EventID e' vuoto -> nessun output (niente da eliminare).
 * Il percorso UPDATE crea comunque nuovi eventi via Remove Duplicates.
 */

const output = [];
for (const item of items) {
  const raw = String(item.json.Calendar_EventID || '').trim();
  const ids = raw.split(/\s+/).filter(id => id.length > 0);
  for (const eid of ids) {
    output.push({ json: { calendarEventIdToDelete: eid } });
  }
}
return output;
